head.script:
/*
 * 화 면 명 : 동부제철오더요청등록
 * 메뉴경로 : 엔콜/오더관리/3자물류/동부제철/
 * ASIS경로 : /ntis/dongwon-ntis-engine/src/main/webapp/ds/tp/dongbusteel/odrmgnt/tp_201_01_02b.jsp(해당화면으로 개발하기로 정소희 책임과 협의)
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-01-18
 * 참고사항 : 1. ds_order와 bind 되는 hidden 컴퍼넌트를 전역변수로 사용하면 서로 값이 SET되는 순간 bind 기능처럼 반대로 SET해야 되므로 해당 화면에서는 적용할수 없어 hidden 컴퍼넌트를 사용함
 *           (교차되게 값을 SET하는 로직이 너무 많음)
 * 
 *           2. 조회 프로세스 변경
 *              - ASIS : tr_reterieve.post() 후 순서는 아래와 같음
 *                가. ds_shipmentIndicationOrderOnRowPosChanged()
 *                나. ds_shipmentIndicationOrder OnLoadCompleted
 *                다. tr_reterieve OnSuccess()
 * 
 *              - TOBE : async로도 순차적으로 처리가 안되서 계약번호 조회를 먼저 수행하도록 처리
 *                가. 계약번호 조회
 *                나. sbm_reterieve_submitdone() : 처음에 ds_shipmentIndicationOrder.setRowPosition() 줘서 ds_shipmentIndicationOrder_onrowpositionchange이 먼저 수행되도록 처리
 *            3. 요청처, 청구처 데이터가 없어도 DB에서 빈로우 한줄이 넘어오기때문에 콤보박스에 "" : "" 표시됨(ASIS는 빈한줄)
 *            4. [작업지시등록] 버튼 삭제 : op_202_02_04b 프로그램 삭제대상
 */

scwin.isParentCalled = false;

scwin.userNm = $c.data.getMemInfo("userNm");
scwin.userMpNo = $c.data.getMemInfo("userMpNo");
scwin.lobranCd = $c.data.getMemInfo("lobranCd");

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd"); // 현재일자
scwin.strNextDate = $c.date.addDate(scwin.strCurDate, 1); // 다음날

scwin.bizDivCntrYn = DsConstants.YN_NO;	 // 사업부문컨테이너여부
scwin.bizDivBulkYn = DsConstants.YN_YES; // 사업부문벌크여부
scwin.bizDivTplYn = DsConstants.YN_YES;	 // 사업부문3자물류여부

// hidden 컴퍼넌트
scwin.hid_ctrtRepClntNo = "";       // 대표거래처번호
scwin.hid_ctrtNo = "";              // 계약번호
scwin.hid_odrJobType = "";          // 오더 작업구분 : 신규(DGauceConstants.TB_JOB_INSERT), 수정(DGauceConstants.TB_JOB_UPDATE)

/* ds_order 관련 hidden 컴퍼넌트
scwin.hid_odrNo = "";               // 오더번호
