scwin.hid_sellYn = "";              // 매출여부
scwin.hid_cntrDsgYn = "";           // 컨테이너지정여부
scwin.hid_repClntNo = "";           // 대표거래처번호
scwin.hid_clntMgntNo = "";          // 거래처관리번호
scwin.hid_transCoNm = "";           // 운송회사명
scwin.hid_transCoTelNo = "";        // 운송회사전화번호
scwin.hid_transCondCd = "";         // 운송조건코드
scwin.hid_cntrWtCondCd = "";        // 컨테이너중량조건코드
scwin.hid_chClsCd = "";             // CH구분코드
scwin.hid_wrkPatternCd = "";        // 작업유형코드
scwin.hid_tsCvsslMgntNo = "";       // TS본선관리번호
scwin.hid_taxnClsCd = "";           // 과세구분코드
scwin.hid_upperOdrNo = "";          // 상위오더번호
scwin.hid_tsVsslCd = "";            // TS선박코드(TS 오더인 경우 적하 선명항차를 관리한다.) 
scwin.hid_tsPortcnt = "";           // TS항차
scwin.hid_tsPortCd = "";            // TS항구코드
scwin.hid_tplCoClsCd = "";          // 3자물류업체구분코드
scwin.hid_odrClsCd = "";            // 오더구분코드
scwin.hid_smsSndYn = "";            // SMS전송여부
scwin.hid_sndDt = "";               // 전송일자
scwin.hid_sndHh = "";               // 전송시간
scwin.hid_odrDcsnYn = "";           // 오더확정여부
scwin.hid_odrDcsnDt = "";           // 오더확정일자
scwin.hid_odrDcsnHh = "";           // 오더확정시간
scwin.hid_odrCompleteYn = "";       // 오더완료여부
scwin.hid_odrCompleteDt = "";       // 오더완료일자
scwin.hid_odrCompleteHh = "";       // 오더완료시간
scwin.hid_odrCnclYn = "";           // 오더취소여부
scwin.hid_odrCnclDt = "";           // 오더취소일자
scwin.hid_odrCnclHh = "";           // 오더취소시간
scwin.hid_odrCnclItemCd = "";       // 오더취소항목코드
scwin.hid_odrCnclRsn = "";          // 오더취소사유
scwin.hid_odrDelYn = "";            // 오더삭제여부
scwin.hid_odrDelDt = "";            // 오더삭제일자
scwin.hid_odrDelHh = "";            // 오더삭제시간
scwin.hid_odrDt = "";               // 오더일자
scwin.hid_odrWrkPathCnt = "";       // 오더작업경로 갯수
scwin.hid_adptExchRt = "";          // 적용환율
scwin.hid_adptExchRtDt = "";        // 적용환율일자
scwin.hid_transCargoClsCd = "";     // 운송화물구분코드
scwin.hid_impExpDomesticClsCd = ""; // 수출입내수구분코드
scwin.hid_regBranCd = "";           // 등록점소코드
scwin.hid_fioBtClsCd = "";          // FIO_BT구분코드(TOBE : 사용안되는것 같음)
scwin.hid_bulkYn = "";              // 벌크여부(TOBE : 사용안되는것 같음)
scwin.hid_crcCd = "";               // 통화코드
scwin.hid_pchsCreatYn = "";         // 매입생성여부
scwin.hid_bilgOdrKndCd = "";        // 청구오더종류코드
scwin.hid_bondTransExpireDt = "";   // 보세운송만료일자
scwin.hid_salesPicNm = "";          // 영업담당자명
scwin.hid_salesPicTelNo = "";       // 영업담당자전화번호
*/

// Popup Check 용 Hidden 값
scwin.hid_chkCtrtClntNo = "";       // 계약처
scwin.hid_chkReqClntNo = "";        // 요청처
scwin.hid_chkBilgClntNo = "";       // 청구처
scwin.hid_chkRealMchtClntNo = "";   // 실화주
scwin.hid_chkDmndNo = "";           // 수요가
scwin.hid_chkSellLodeptCd = "";     // 매출부서
scwin.hid_chkBilgLodeptCd = "";     // 청구부서
scwin.hid_chkLineCd = "";           // LINE
scwin.hid_chkBlNo = "";             // B/L 번호
scwin.hid_chkCvsslMgntNo = "";      // 본선관리번호
scwin.hid_chkDptWrkPlCd = "";       // 출발작업장
scwin.hid_chkArvWrkPlCd = "";       // 도착작업장
scwin.hid_chkReterieve = "";        // 조회 여부 확인

// EDI 맵핑 조회조건 용 Hidden 값
scwin.hid_docCd = "ODRKND_001";     // 문서코드 - 화주오더종류
scwin.hid_wrkPlCd = "999";          // 작업장코드 
scwin.hid_itemCd = "";              // 항목코드 
scwin.hid_osideCd = "";             // 외부코드

// 조회조건 용 logseq 값
scwin.hid_logSeq = "";

scwin.defaultFontColor = "#000000";

scwin.vaildObj = new Array(); // Vaildation 확인 Object 설정
scwin.ds_mchtOdrKndCd_reterieveYn = "N";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    const parentYn = $p.parent()?.scwin?.params;
    if(parentYn&&parentYn.clntNo){
        scwin.isParentCalled = true;
    }
    // 공통코드 콤보박스 SET
    const codeOptions = [
        { grpCd: "SD114", compID: "acb_selfClsCd" } //자가/합적/확정 콤보박스
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    //$p.setTimeout(function () {
    // 거래처명, 출발작업장, 도착작업장 readOnly(ASIS : class=input_textKorReadOnly)
    // ed_clntNm.setReadOnly(true);        // 조회조건 - 거래처
    // ed_dmndNm.setReadOnly(true);        // 수요가
    // ed_sellLodeptNm.setReadOnly(true);  // 매출부서
    // ed_bilgLodeptNm.setReadOnly(true);  // 청구부서
    // ed_dptWrkPlNm.setReadOnly(true);    // 출발작업장
    // ed_arvWrkPlNm.setReadOnly(true);    // 도착작업장        
    // 초기화
    await scwin.f_defaultValue();

    //다른탭에서 넘어왔을 때 활성화 되는 버튼  
    if(scwin.isParentCalled){
        btn_delete.show();
        grp_lastArea.show();
    }else{//메뉴찍어서 오면 비활성화
        btn_delete.hide();
        grp_lastArea.hide();
    }

    // 탭 선택 호출
    //if (parent.document.readyState == "interactive" || parent.document.readyState == "complete")
    //    parent.scwin.f_selectTabMenu(0); // 상위 Tab 페이지의 초기화가 완료되었을때

    $p.parent().scwin.f_selectTabMenu(0);
    //}, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function () {
    scwin.f_dsOrderSearchHeader();		// 오더 조회조건
    scwin.f_dsOrderQueryConditionHeader(); // 오더 조회조건 - 계약 거래처 조회    
    scwin.f_dsLobranQueryConditionHeader(); // 물류점소

    // 조회 조건용 logSeq 초기값
    scwin.hid_logSeq = $p.parent().scwin.hid_logSeq;

    // 조회 조건 초기화
    scwin.f_FieldClear();

    // 출발일자, 도착일자 초기값 설정
    ica_wrkStDt.setValue(scwin.strCurDate);
    ica_wrkEndDt.setValue(scwin.strNextDate);

    // 오더 담당 정보 설정
    ed_odrPicNm.setValue(scwin.userNm);
    ed_odrPicTelNo.setValue(scwin.userMpNo);

    var temp_lobranCd = dma_lobranQueryCondition.get("lobranCd").trim().substring(0, 2);
    // 일단 여기다가는 하드코딩.....
    // 로그인 사용자가 인천지점 근무자일 경우는....무조건 4A5로 셋팅한다...
    // 이거 나중에는 상수class에 담아 놓으면 좋다...
    if (temp_lobranCd == '4A') {
        // 로그인 사용자 물류점소 - 영업(청구)부서 조회
        dma_lobranQueryCondition.set("deptmentCd", "5"); // 영업부서
        await $c.sbm.execute(sbm_retrieveLobranSales);

        // 로그인 사용자 물류점소 - 운송(매출)부서 조회
        dma_lobranQueryCondition.set("deptmentCd", "5"); // 운송부서
        await $c.sbm.execute(sbm_retrieveLobranTrans);
    } else {
        // 로그인 사용자 물류점소 - 영업(청구)부서 조회
        dma_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT); // 영업부서
        await $c.sbm.execute(sbm_retrieveLobranSales);

        // 로그인 사용자 물류점소 - 운송(매출)부서 조회
        dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT); // 운송부서
        await $c.sbm.execute(sbm_retrieveLobranTrans);
    }

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    // PopUp 이미지 버튼을 비활성화 시킨다.
    scwin.f_DisablePopUpObj();

    // 오더 확정 버튼 비활성화
    $c.gus.cfDisableObjects([btn_confirmOrder]);

    $c.gus.cfEnableObjects([btn_PopUp1]);

    // 그리드 행추가 / 삭제 /취소 버튼 비활성화
    $c.gus.cfDisableAllBtn();

    // 오더 종류에 따른 화면 설정
    scwin.f_defaultOdrKndSetting();

    // Tab 오더정보 초기화
    scwin.f_clearTabOrderInfo();

    $c.gus.cfDisableObjects(tbl_order);

    tbx_totalRows.setValue(0);

    $c.gus.cfEnableBtnOnly([btn_copy, btn_add]);

    //ed_clntNo.focus();
    //$p.parent().hid_frameLoad.value = 0;

    //ed_clntNo.setValue("124992");
    //ed_mchtOdrNo.setValue("1001359375");
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_searchCondition);

    // TOBE : 맨처음 조회시에는 포커스 안가게 처리(포커스가가면 화주오더종류가 다시 조회됨)
    if (scwin.ds_mchtOdrKndCd_reterieveYn == "Y") {
        ed_clntNo.focus();
    }
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 오더 조회조건
//-------------------------------------------------------------------------
scwin.f_dsOrderSearchHeader = function () {
    ds_orderSearch.insertRow(0);
    ds_orderSearch.setRowPosition(0);
};

//-------------------------------------------------------------------------
// 청구 거래처 조회 조건 SET
//-------------------------------------------------------------------------
scwin.f_dsOrderQueryConditionHeader = function () {
    dma_orderQueryCondition.set("bizDivCntrYn", scwin.bizDivCntrYn);
    dma_orderQueryCondition.set("bizDivBulkYn", scwin.bizDivBulkYn);
    dma_orderQueryCondition.set("bizDivTplYn", scwin.bizDivTplYn);
};

//-------------------------------------------------------------------------
// 물류점소 영업부서 조회 조건 SET
//-------------------------------------------------------------------------
scwin.f_dsLobranQueryConditionHeader = function () {
    dma_lobranQueryCondition.set("lobranCd", scwin.lobranCd);
    dma_lobranQueryCondition.set("lobranClsCd", "T");
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT); // 영업부서
    dma_lobranQueryCondition.set("useYn", DsConstants.YN_YES);
};

//-------------------------------------------------------------------------
// 계약거래처 DataSet을 초기화
//-------------------------------------------------------------------------
scwin.f_clearDataSetRetrieveCtrtClnt = function () {
    dma_retrieveCtrtClnt.set("ctrtClntNo", "");
    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.bizDivCntrYn);
    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.bizDivBulkYn);
    dma_retrieveCtrtClnt.set("bizDivTplYn", scwin.bizDivTplYn);
    dma_retrieveCtrtClnt.set("impExpDomesticClsCd", DsConstants.DOMESTIC_CD);
};

//-------------------------------------------------------------------------
// Data 초기화 (HTML INPUT)
//-------------------------------------------------------------------------
scwin.f_clearData = function () {
    // Order Master DataSet 값 초기화 -> TOBE에서 number값도 0으로 초기화 안되고 빈값으로 되어 해당 로직 주석처리
    // for (var i = 0; i < ds_order.getTotalCol(); i++) {
    //     ds_order.setCellData(ds_order.getRowPosition(), ds_order.getColumnID(i), "");
    // }

    ed_bilgLodeptNm.setValue("");
    ed_sellLodeptNm.setValue("");
    ed_dptWrkPlNm.setValue("");
    ed_arvWrkPlNm.setValue("");

    ed_dptWrkPlNm.hidVal = "";
    ed_arvWrkPlNm.hidVal = "";

    hid_odrKndCd.setValue(acb_odrKndCd.getValue()); // 오더종류
    acb_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS); // 자가구분코드 - 벌크오더(당사운송:LI)

    scwin.hid_bizDivCntrYn = scwin.bizDivCntrYn; // 사업부문컨테이너여부
    scwin.hid_bizDivBulkYn = scwin.bizDivBulkYn; // 사업부문벌크여부
    scwin.hid_bizDivTplYn = scwin.bizDivTplYn; // 사업부문3자물류여부
    hid_sellYn.setValue(DsConstants.YN_YES); // 매출여부
    hid_cntrDsgYn.setValue(DsConstants.YN_NO); // 컨테이너지정여부
    hid_transCargoClsCd.setValue(DsConstants.ODR_BULK); // 운송화물구분코드
    //scwin.hid_impExpDomesticClsCd = acb_odrKndCd.getValue("fltrCd2", acb_odrKndCd.Index); // 수출입내수구분코드
    hid_impExpDomesticClsCd.setValue(ds_odrKndCd.getCellData(acb_odrKndCd.getSelectedIndex(), "fltrCd2")); // 수출입내수구분코드    

    hid_odrClsCd.setValue(DsConstants.YN_NO); // 오더구분코드
    hid_smsSndYn.setValue(DsConstants.YN_NO); // SMS전송여부
    hid_odrDcsnYn.setValue(DsConstants.YN_NO); // 오더확정여부
    hid_odrCnclYn.setValue(DsConstants.YN_NO); // 오더취소여부
    hid_odrCompleteYn.setValue(DsConstants.YN_NO); // 오더완료여부
    hid_regBranCd.setValue(scwin.lobranCd); // 등록점소 - 사용자 설정 물류점소

    hid_salesPicNm.setValue(""); // 영업담당자명
    hid_salesPicTelNo.setValue(""); // 영업담당자 전화번호

    // EMEDIT 팝업 확인을 위한 HIDDEN 초기화
    scwin.hid_chkCtrtClntNo = ""; // 계약처
    scwin.hid_chkReqClntNo = ""; // 요청처
