//-------------------------------------------------------------------------
// 선택된 오더 유형별 화면 설정을 변경한다.
//-------------------------------------------------------------------------
scwin.f_setDisplayOdrKndCd = function (odrKndCd) {

    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_ODR: // 내수 거점내 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_OUTSIDE_ODR: // 내수 거점간 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_FCTY_CRRYOUT_ODR: // 내수 공장반출 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LOGIS_BASE_CRRYOUT_ODR: // 내수 물류기지반출 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_RETRV_ODR: // 내수 거점간회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_FCTY_OUTSIDE_RETRV_ODR: // 내수 공장회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LOGIS_BASE_RETRV_ODR: // 내수 물류기지회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LDULD_ODR: // 내수 상하차 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_STR_ODR: // 내수 보관 오더
        case DsConstants.ODR_KND_CD_PIER_WAGES_ODR: // 부두노임 오더
        case DsConstants.ODR_KND_CD_PIER_YARD_WAGES_ODR: // 부두 장치장 노임 오더
        case DsConstants.ODR_KND_CD_COMMON_USE_YARD_WAGES_ODR: // 상용 장치장 노임 오더
        case DsConstants.ODR_KND_CD_MONTH_PUBLIC_CHARGES_WAGES_ODR: // 월 제세공과성 노임 오더
        case DsConstants.ODR_KND_CD_PACK_ODR: // 포장 오더
            scwin.cf_ShowObject([tbx_dmndNo_01, udc_dmndNo]); // 수요가
            scwin.cf_ShowObject([tr_picNm_picTelNo]); // 상차담당, 하차담당, 오더담당
            scwin.cf_ShowObject([grp_arvWrkPlCd]); // 도착작업장
            scwin.cf_ShowObject([tbx_wrkStDtHh_01, grp_wrkStDtHh_02]); // 출발일자, 출발시간
            scwin.cf_ShowObject([tbx_wrkEndDtHh_01, grp_wrkEndDtHh_02]); // 도착일자, 도착시간           

            // Vaildation 확인용 Object 설정
            scwin.vaildObj = new Array(acb_odrKndCd
                , lc_ctrtNo
                , ed_reqClntNo
                , ed_bilgClntNo
                , ed_sellLodeptCd
                , ed_bilgLodeptCd
                , ed_dptWrkPlCd
                , ed_dptDtl
                , ed_arvWrkPlCd
                , ed_arvDtl
                , ed_onPicNm
                , ed_onPicTelNo
                , ed_offPicNm
                , ed_offPicTelNo
                , ed_odrPicNm
                , ed_odrPicTelNo
                , ica_wrkStDt
                , ed_wrkStHh
                , ica_wrkEndDt
                , ed_wrkEndHh
                , txt_rmk
            );

            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 컴포넌트 Show
//-------------------------------------------------------------------------
scwin.cf_ShowObject = function (objArray) {
    objArray.forEach((obj) => {
        obj.show('');
    });
};

//-------------------------------------------------------------------------
// 컴포넌트 Hide
//-------------------------------------------------------------------------
scwin.cf_HideObject = function (objArray) {
    objArray.forEach((obj) => {
        obj.hide();
    });
};

