//-------------------------------------------------------------------------
//시작시간, 종료시간 유효성 체크 - 동일한 경우 포함
//-------------------------------------------------------------------------
scwin.f_chkTime = function (strDate, strTime, endDate, endTime) {
    var differTime = (endDate + endTime) - (strDate + strTime);

    if (differTime >= 0) { return true; }
    else { return false; }
}

//-------------------------------------------------------------------------
//시작시간, 종료시간 유효성 체크 - 동일한 경우 오류
//-------------------------------------------------------------------------
scwin.f_chkTimeNotEqual = function (strDate, strTime, endDate, endTime) {
    var differTime = (endDate + endTime) - (strDate + strTime);

    if (differTime > 0) { return true; }
    else { return false; }
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    var clntNo = ed_clntNo.getValue().replace(/\s*$/, '');
    var mchtOdrKndCd = acb_mchtOdrKndCd.getValue();
    var mchtOdrNo = ed_mchtOdrNo.getValue().replace(/\s*$/, '');
    var mcomOdrNo = ed_mcomOdrNo.getValue().replace(/\s*$/, '');

    if ($c.gus.cfIsNull(mcomOdrNo)) {
        if (!$c.gus.cfIsNull(clntNo)) { // 계약거래처가 지정된 경우
            if ($c.gus.cfIsNull(mchtOdrKndCd)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("화주오더종류"));
                acb_mchtOdrKndCd.focus();
                return;
            }

            if ($c.gus.cfIsNull(mchtOdrNo)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("화주오더번호"));
                ed_mchtOdrNo.focus();
                return;
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("계약거래처 또는 당사오더번호"));
            ed_clntNo.focus();
            return;
        }
    } else {
        if (!$c.gus.cfValidate(ed_mcomOdrNo)) {
            return;
        }
    }

    // DataSet 초기화
    scwin.f_clearDataSetAll();

    ds_orderSearch.setCellData(0, "repClntNo", scwin.hid_ctrtRepClntNo);
    ds_orderSearch.setCellData(0, "docCd", scwin.hid_docCd);
    ds_orderSearch.setCellData(0, "wrkPlCd", scwin.hid_wrkPlCd);
    ds_orderSearch.setCellData(0, "itemCd", scwin.hid_itemCd);
    ds_orderSearch.setCellData(0, "osideCd", scwin.hid_osideCd);
    ds_orderSearch.setCellData(0, "logSeq", scwin.hid_logSeq);
    ds_orderSearch.setCellData(0, "logSeq", "0");

    $c.sbm.execute(sbm_reterieve);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();
    $c.gus.cfDisableAllBtn();
    $c.gus.cfEnableBtnOnly([btn_save]);
    $c.gus.cfEnableBtnOnly([btn_delete]);
    $c.gus.cfEnableBtnOnly([btn_copy, btn_add]);
    $c.gus.cfDisableBtnOnly([btn_update]);
    scwin.hid_odrJobType == DGauceConstants.TB_JOB_UPDATE;

    // PopUp 이미지 버튼을 활성화 시킨다.
    scwin.f_EnablePopUpObj();

    $c.gus.cfEnableObjects([tbl_order]);
    $c.gus.cfDisableObjects([acb_odrKndCd, lc_ctrtNo]);

    if (hid_odrWrkPathCnt.getValue() > 0 && hid_odrWrkPathCnt.getValue() == ds_orderCommodity.getRowCount() && hid_odrDcsnYn.getValue() != DsConstants.YN_YES && hid_odrDelYn.getValue() != DsConstants.YN_YES) {
        // 오더 확정 버튼 활성화
        $c.gus.cfEnableObjects([btn_confirmOrder]);
    }

    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    if (scwin.f_chkResultsConfirmation()) {
        // 수정불가 항목을 Disable 한다.
        // 수정 불가항목 : 오더번호, 오더종류, 계약거래처, 계약번호, 대표거래처
        // , 출발작업장, 도착작업장, 작업시작일자, 작업시작시간, 작업종료일자, 작업종료시간
        // , 자가구분, 작업유형, 합적여부 (벌크오더 화면에는 해당되지 않는다.
        $c.gus.cfDisableObjects([ed_dptWrkPlCd, ed_dptWrkPlNm, ed_arvWrkPlCd, ed_arvWrkPlNm, ica_wrkStDt, ed_wrkStHh, ica_wrkEndDt, ed_wrkEndHh, acb_wrkPatternCd, rd_coshippingYn]);
    }
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    // 대표 거래처 정보 설정
    if ($c.gus.cfIsNull(hid_repClntNo.getValue()))
        hid_repClntNo.setValue(scwin.hid_ctrtRepClntNo);

    // 작업구분에 따른 확인
    if (scwin.hid_odrJobType == DGauceConstants.TB_JOB_INSERT) {
        // INSERT
        if (ds_order.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더기본정보"));
            return false;
        }

        if (ds_orderCommodity.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더품목정보"));
            return false;
        }

        /*20160126 화물위탁증 관련 추가*/
        ds_order.setCellData(0, "trnsRealMchtClntNm", "동부인천스틸 주식회사");
        ds_order.setCellData(0, "trnsRealMchtClntTelNo", "02-3450-8450");

        $c.sbm.setAction(sbm_save, "/ncall.ds.tp.dongbusteel.odrmgnt.RegistShipmentIndicationOrderRequestCMD.do");

        // 오더요청 기본정보 Update 설정
        var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");
        for (var i = 0; i < ds_shipmentIndicationOrder.getRowCount(); i++) {
            if (v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                ds_shipmentIndicationOrder.setCellData(i, "rowStatus", DGauceConstants.TB_JOB_UPDATE);
                ds_shipmentIndicationOrder.setCellData(i, "wrkStDt", ica_wrkStDt.getValue()); // 출발일자 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkStHh", ed_wrkStHh.getValue()); // 출발시간 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkEndDt", ica_wrkEndDt.getValue()); // 도착일자 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue()); // 도착시간 설정
            } else {
                break;
            }
        }

        // 품명 1건인 경우 합적할수 없습니다.
        if (ds_orderCommodity.getRowCount() == 1 && rd_coshippingYn.getValue() == "1") {
            $c.gus.cfAlertMsg(MSG_CM_ERR_041, new Array("오더품목정보가 1건인 경우", "합적"));
            return false;
        }

    } else {
        // UPDATE        
        if (ds_order.getModifiedIndex().length == 0 && ds_orderCommodity.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더정보"));
            return false;
        }

        $c.sbm.setAction(sbm_save, "/ncall.ds.tp.dongbusteel.odrmgnt.UpdateShipmentIndicationOrderRequestCMD.do");

        // 오더요청 정보 Update 설정
        var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");
        for (var i = 0; i < ds_shipmentIndicationOrder.getRowCount(); i++) {
            if (v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                if (v_logSeq == ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                    ds_shipmentIndicationOrder.setCellData(i, "rowStatus", DGauceConstants.TB_JOB_UPDATE);
                } else if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(i, "mcomOdrNo"))) {
                    //ds_shipmentIndicationOrder.getCellData(i, "rowStatus") = DGauceConstants.TB_JOB_UPDATE;          
                } else {
                    await $c.gus.cfAlertMsg("이전 오더요청 오더에 대한 작업이 진행되지 않았습니다.");
                    ds_shipmentIndicationOrder.setRowPosition(i);
                    return false;
                }
            } else {
                break;
            }
        }

        // 출발일자/시간, 도착일자/시간 변경시 품명 작업시작일자/시간, 작업완료일자/시간 설정
        if (ds_order.getCellData(ds_order.getRowPosition(), "wrkStDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStDt")
            || ds_order.getCellData(ds_order.getRowPosition(), "wrkStHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStHh")
            || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndDt")
            || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndHh")) {

            // 품명 데이터 셋에서 해당 품명을 찾아 정보를 변경
            for (j = 0; j < ds_orderCommodity.getRowCount(); j++) {
                ds_orderCommodity.setCellData(j, "wrkStDt", ica_wrkStDt.getValue()); // 작업시작일자
                ds_orderCommodity.setCellData(j, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                ds_orderCommodity.setCellData(j, "wrkEndDt", ica_wrkEndDt.getValue()); // 작업종료일자
                ds_orderCommodity.setCellData(j, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간
            }
        }
    }

    // 필수 입력사항을 체크
    if (await scwin.f_validChk()) {
        //let ret = await $c.win.confirm(MSG_CM_CRM_001, new Array("오더정보"));
        let ret = await $c.win.confirm(MSG_CM_CRM_001);

        if (ret) {
            //Eidt 속성을 Disable로 변경한다.
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableAllBtn();

            // ASIS hidden 컴퍼넌트 바인드 처리(IN_DS 될때) 
            //scwin.bind_ds_order();

            $c.sbm.execute(sbm_save);
        }
    }
};

//-------------------------------------------------------------------------
// 저장전 validation check - 오더 정보
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    let ret = await $c.gus.cfValidate(scwin.vaildObj)
    if (ret) {
        if (grp_wrkEndDtHh_02.getStyle("display") != "none") {
            // 출발작업일자가 도착작업일자보다 큰 경우
            if (ica_wrkStDt.getValue().trim() > ica_wrkEndDt.getValue().trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_048, new Array("출발작업일자", "도착작업일자"));
                ica_wrkEndDt.focus();
                return false;
            }

            // 출발작업시간이 도착작업시간보다 큰 경우
            if (ica_wrkStDt.getValue().trim() == ica_wrkEndDt.getValue().trim() && ed_wrkStHh.getValue().trim() >= ed_wrkEndHh.getValue().trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_057, new Array("도착작업시간", "출발작업시간"));
                ed_wrkEndHh.focus();
                return false;
            }

        }

        // 상차, 하차, 오더 담당 전화번호 유효성 확인
        if (tr_picNm_picTelNo.getStyle("display") != "none") {
            if (ed_onPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_onPicTelNo))
                return false;

            if (ed_offPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_offPicTelNo))
                return false;

            if (ed_odrPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_odrPicTelNo))
                return false;

        }

        for (var i = 0; i < ds_orderCommodity.getRowCount(); i++) {
            // 수량, 중량, CBM 중 한가지는 입력하여야 합니다.
            if (ds_orderCommodity.getCellData(i, "qty") == 0
                && ds_orderCommodity.getCellData(i, "grossWt") == 0
                && ds_orderCommodity.getCellData(i, "cbm") == 0) {

                await $c.gus.cfAlertMsg("수량, 중량, CBM 중 한가지는 입력하셔야 합니다.");
                ds_orderCommodity.setRowPosition(i);
                //gr_orderCommodity.SetColumn("qty"); TOBE : 해당 그리드 없음
                return false;
            }

            // 품명의 출발일자, 출발시간, 도착일자, 도착시간 정보를 오더 출발일시, 도착일시로 설정한다.
            ds_orderCommodity.setCellData(i, "wrkStDt", ica_wrkStDt.getValue());
            ds_orderCommodity.setCellData(i, "wrkStHh", ed_wrkStHh.getValue());
            ds_orderCommodity.setCellData(i, "wrkEndDt", ica_wrkEndDt.getValue());
            ds_orderCommodity.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue());

            // 필수 항목 확인 - 품명 정보 설정 확인
            if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "commCd"))) {
                $c.gus.cfAlertMsg(MSG_CM_WRN_018, new Array("품명", "EDI MAPPING 정보"));
                return false;
            }
        }

        return true;
    } else {
        return false;
    }
};

//-------------------------------------------------------------------------
// 오더요청 정보를 오더 정보에 설정
//-------------------------------------------------------------------------
scwin.f_setOrderInformation = async function (jobType) {
    if ($c.gus.cfIsNull(jobType)) return; // jobType 이 설정되지 않은 경우
    if (ds_shipmentIndicationOrder.getRowCount() == 0) return; // 오더요청 정보가 존재하지 않는 경우

    switch (jobType) {
        case DGauceConstants.TB_JOB_INSERT: // INSERT
            // 오더 정보 설정
            if (ds_shipmentIndicationOrder.getRowCount() > 0 && ds_order.getRowCount() == 0) {
                var s_row = ds_shipmentIndicationOrder.getRowPosition();

                // 오더 정보가 존재하지 않는 경우 오더 정보 추가
                ds_order.setJSON([]);
                ds_order.insertRow(0);
                ds_order.setRowPosition(0)
                scwin.f_clearData();

                if (ds_ctrtNo.getRowCount() == 0) { // 계약번호 조회
                    hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo"));

                    dma_retrieveCtrtClnt.set("ctrtClntNo", hid_ctrtClntNo.getValue());
                    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
                    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);

                    $c.sbm.execute(sbm_retrieveCtrtClnt);

                    scwin.sbm_retrieveCtrtClnt_submitdone();
                }

                hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo")); // 계약거래처번호
                hid_ctrtClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNm")); // 계약거래처번호
                hid_realMchtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo")); // 계약거래처번호
                hid_crcCd.setValue("KRW"); // 공통 통화코드
                hid_clntMgntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrNo")); // 거래처관리번호 <- 화주오더번호

                ed_dmndNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo")); // 고객 -> 수요가
                ed_dmndNo.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo"); // 고객 -> 수요가
                ed_dmndNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm"));
