                    }
                }

                hid_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));
                acb_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));

                ed_offPicNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "accp"));
                ed_offPicTelNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "tplTelNo")); // 전화번호

                txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm")); // 특이사항
            }

            break;

        case DGauceConstants.TB_JOB_DELETE: // DELETE

            break;
        default:

            break;
    }

};

//-------------------------------------------------------------------------
// 시간(HHmmss) 형식의 값인지 확인
//-------------------------------------------------------------------------
scwin.isTime = function (sTime) {
    let flag = true;
    try {
        if (sTime.length != 6) {
            return false;
        }
        const h1 = parseInt(sTime.substring(0, 2), 10);
        const t1 = parseInt(sTime.substring(2, 4), 10);
        const s1 = parseInt(sTime.substring(4), 10);

        if (isNaN(h1) || isNaN(t1) || isNaN(s1))
            flag = false;

        if (h1 + t1 + s1 != "") {
            if (h1 < 0 || h1 > 24) {
                flag = false;
            } else if (h1 == 24) {
                if (typeof timeChk == "boolean" && !timeChk)
                    flag = false;
                if (t1 > 0)
                    flag = false;
                if (s1 > 0)
                    flag = false;
            }
            if (t1 < 0 || t1 > 59)
                flag = false;
            if (s1 < 0 || s1 > 59)
                flag = false;
        }
    } catch (ex) {
        console.error(ex);
        flag = false;
    }
    return flag;
};

