//-------------------------------------------------------------------------
// 오더 N건 복사 
//-------------------------------------------------------------------------
scwin.f_odrCopy = async function () {
    if (ed_mcomOdrNo.getValue() == "") {
        $c.win.alert("오더 생성 후 오더분할 기능을 사용하세요");
        return false;
    }
    if (ds_order.getCellData(0, "odrDcsnYn") == "0") {
        $c.win.alert("오더 확정 후 오더분할 기능을 사용하세요");
        return false;
    }
    if (ds_shipmentIndicationCommodity.getRowCount() > 1) {
        $c.win.alert("오더분할은 품명이 1개인 오더에 대해서만 진행 가능합니다.");
        return false;
    }

    if (parseFloat(ed_copyKg.getValue()) < 1000 || parseFloat(ed_copyKg.getValue()) > parseFloat(ed_copyWt.getValue())) {
        $c.win.alert("분할 Kg에 1000보다 작은 값을 입력했습니다. 유효한 숫자를 입력해 주세요");
        ed_copyKg.focus();
        return false;
    }

    ds_order.setCellData(0, "odrCopyEachWt", ed_copyKg.getValue());
    ds_order.setCellData(0, "odrCopyWt", ed_copyWt.getValue());
    ds_order.setCellData(0, "copyClsCd", "D");

    ds_copiedOdr.setJSON([]);
    $c.sbm.execute(sbm_odrCopy);
};

