//-------------------------------------------------------------------------
// 오더 계약번호 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_ctrtNo event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_ctrtNo_OnLoadCompleted = function () {
    if (ds_orderCommodity.getRowCount() > 0 && ds_orderCommodity.getRowCount() == 1) {
        rd_coshippingYn.setValue('0');
    } else {
        rd_coshippingYn.setValue('1');
    }

    var sub_lobran = dma_lobranQueryCondition.get("lobranCd").trim().substring(0, 2);
    if (sub_lobran == '3A') {
        ed_bilgLodeptCd.setValue("3A2");
        ed_bilgLodeptCd.hidVal = "3A2";
        ed_bilgLodeptNm.setValue("당진평택운송");
        ed_bilgLodeptNm.hidVal = "당진평택운송";
    } else if (sub_lobran == '7A') {
        ed_bilgLodeptCd.setValue("7A2");
        ed_bilgLodeptCd.hidVal = "7A2";
        ed_bilgLodeptNm.setValue("포항운송");
        ed_bilgLodeptNm.hidVal = "포항운송";
    }
};

//-------------------------------------------------------------------------
// 요청 거래처 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
