//-------------------------------------------------------------------------
// 오더요청 품명 filter
// ASIS : ds_shipmentIndicationCommodity event=OnFilter(row)
//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationCommodity_OnFilter = function (row) {
    var v_mchtOdrKndCd = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd");
    var v_mchtOdrNo = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrNo");
    var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");

    // 필터 삭제 후 적용
    ds_shipmentIndicationCommodity.removeColumnFilterAll();
    $c.data.dataListFilter(ds_shipmentIndicationCommodity, "mchtOdrKndCd=='" + v_mchtOdrKndCd + "' && mchtOdrNo=='" + v_mchtOdrNo + "' && logSeq=='" + v_logSeq + "'");
};

//-------------------------------------------------------------------------
// 거래처 UDC START
//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'F', 'F');
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, ed_clntNm, 1, true);
};

scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_clntNo, 1, false);
};

scwin.udc_clntNo_callBackFunc = async function (rtnList) {
    //거래처코드 거래처명
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);

    // 거래처 선택시 화주오더종류를 조회한다.
    if (rtnList != null && rtnList[0] != "N/A") {
        scwin.hid_ctrtRepClntNo = rtnList[2];

        // TOBE : ASIS는 rtnList[2]가 null인데도 아래문장이 false이기 때문에 아예 실행이 안됨
        // if ($c.gus.cfIsNull(scwin.hid_ctrtRepClntNo))
        //     scwin.hid_ctrtRepClntNo = ed_clntNo.getValue();

        // EDI MAPPING 조회 조건
        dma_ediMappingSearch.set("docCd", scwin.hid_docCd);
        dma_ediMappingSearch.set("wrkPlCd", scwin.hid_wrkPlCd);
        dma_ediMappingSearch.set("clntNo", scwin.hid_ctrtRepClntNo); //거래처번호
        dma_ediMappingSearch.set("ctrtNo", lc_ctrtNo.getValue()); //계약번호
        // await $c.sbm.execute(sbm_reterieveMchtOdrKnd);
        $c.sbm.execute(sbm_reterieveMchtOdrKnd);
    }
};
