};

scwin.ed_copyKg_onblur = function (e) {
    ed_copyCnt.setValue(Math.ceil(parseFloat(ed_copyWt.getValue()) / parseFloat(ed_copyKg.getValue())));
};

scwin.combineLabel = function(label,value) {
    if (!value) return label;

    const idx = ds_ctrtNo.getMatchedIndex("ctrtNo", value)[0];
    if (idx !== undefined) {
        const rowData = ds_ctrtNo.getRowJSON(idx);
        return `${rowData.ctrtNo}(${rowData.clntPicNm}:~${rowData.ctrtEndDt})`;
    }
    return label;
};

