    //ed_mchtOdrNo
    let ret = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, new Array(hid_odrNo.getValue())));
    if (ret) {
        $c.sbm.execute(sbm_delete);
    }
};

